import sys, usb.core
# they are my home device codes. you should use rooted android device and frida code to extract them.
# sudo python3 ir_blast.py -- ac_power_on
cmds = {
"ac_power_on": "",
"ac_power_off":"",


"tv_ok":"ffffffff36ef29ff71236a2323ffffff8e239423236a01236a2323000023230001236a236a002323002323232300000001232301236a00236a01010001237f2300236a23ffea028e23942301236a010023230000232301236a01000000002323232300000100236a236a000101236a00236a232300236a23ecec02",
"tv_on_off":"ffffffff36ef29ff05236a2323ffffff8f239423010101002323002323000101010000000000000100000000002323236a000101010101012385eb028f230393230101236a000000000001236a01002323232300000001000000000000010001010101010123f9ec02",
"tv_volume_up":"ffffffff36ef29fff1226a2224ffffff9523a12301010122242224000000226a0101000000222400226a226a226a0000000000000000226a226a226a01017322f5ed029523a123226a226a01222400000000226a226a226a0000000022240101226a22240000222400222422242224226a01226a010122f0ee02",
"tv_volume_down":"ffffffff36ef29ffe9226a2224ffffff9623a023226a01226a2224222400000001226a0100000000000101000100000000000001000101226a0122f3ed027d9623a023226a226a226a222400000000226a01226a22242224000000010100012224000000000001000101226a226a2291ef02",  
}

if len(sys.argv) < 2: sys.exit("Error: No command provided.")
cmd = sys.argv[-1].lstrip('-')
if cmd not in cmds: sys.exit(f"Error: Command '{cmd}' not found.")

dev = usb.core.find(idVendor=0x045c)
if not dev: sys.exit("Error: Device not found.")

for i in (0, 1):
    try:
        if dev.is_kernel_driver_active(i): dev.detach_kernel_driver(i)
    except: pass

dev.set_configuration()
print(f"[*] Sending '{cmd}'...")

for p in ("fcfcfcfc", "fafafafa"): 
    dev.write(0x02, bytes.fromhex(p))

payload = cmds[cmd]
for i in range(0, len(payload), 126):
    dev.write(0x02, bytes.fromhex(payload[i:i+126]))

try: dev.read(0x82, 64, timeout=100)
except: pass

print("[+] Done.")
